  <script type="module">
    // ======== 强绑定的标签页切换逻辑 ========
    window.switchSurvivalTab = function(tabId, btnElement) {
      const terminal = btnElement.closest('.survival-terminal');
      if (!terminal) return;

      const allBtns = terminal.querySelectorAll('.tab-btn');
      allBtns.forEach(b => b.classList.remove('active'));
      btnElement.classList.add('active');

      const allContents = terminal.querySelectorAll('.tab-content');
      allContents.forEach(c => c.classList.remove('active'));

      const targetContent = terminal.querySelector(`#${tabId}`);
      if (targetContent) {
        targetContent.classList.add('active');
      }
    };

    // ======== MVU 数据填充逻辑 ========
    function populateCharacterData() {
      const all_variables = typeof getAllVariables === 'function' ? getAllVariables() : {};

      // === 世界状态 ===
      const time = _.get(all_variables, 'stat_data.世界.当前时间', '00:00');
      const stage = _.get(all_variables, 'stat_data.世界.游戏阶段', '探索中');
      const enemy = _.get(all_variables, 'stat_data.世界.敌人阵营', '未知');
      const location = _.get(all_variables, 'stat_data.世界.当前位置', '客房');

      $('#sys-time').text(time);
      $('#sys-stage').text(stage);
      $('#sys-enemy').text(enemy);
      $('#sys-location').text(location);

      if(stage === '遭遇战' || stage === '被捕获') {
        $('#sys-stage').addClass('val-danger');
      } else {
        $('#sys-stage').removeClass('val-danger');
      }

      // === 玩家状态 ===
      const hp = _.get(all_variables, 'stat_data.玩家.体力值', 100);
      const injury = _.get(all_variables, 'stat_data.玩家.伤残等级', '无伤');
      const trait = _.get(all_variables, 'stat_data.玩家.被动特质', '无');
      const controlLoss = _.get(all_variables, 'stat_data.玩家.生理失控度', 0);

      $('#player-hp').text(hp + '%');
      $('#player-injury').text(injury);
      $('#player-trait').text(trait);
      $('#player-control').text(controlLoss + '%');

      // 更新进度条
      $('#hp-bar').css('width', hp + '%');
      $('#control-bar').css('width', controlLoss + '%');

      // 颜色判定
      $('#player-hp').toggleClass('val-warning', hp <= 50 && hp > 20).toggleClass('val-danger', hp <= 20);
      if(hp <= 20) $('#hp-bar').addClass('danger'); else $('#hp-bar').removeClass('danger');

      $('#player-injury').toggleClass('val-warning', injury === '中度').toggleClass('val-danger', injury === '重度');
      $('#player-control').toggleClass('val-warning', controlLoss >= 50 && controlLoss < 80).toggleClass('val-danger', controlLoss >= 80);

      // === 装备栏 ===
      const equip = _.get(all_variables, 'stat_data.玩家.装备栏', {});
      $('#eq-hand').text(equip?.手持物 || '空');
      $('#eq-consumable').text(equip?.消耗品 || '空');
      $('#eq-wear').text(equip?.穿戴物 || '日常衣物');

      // === 同伴名单 ===
      const companions = _.get(all_variables, 'stat_data.同伴名单', {});
      const cNames = ['布拉德', '杰西卡', '克里斯', '艾米丽'];

      cNames.forEach(name => {
        const status = _.get(companions, name, '未知');
        const idName = `comp-${name}`;
        $(`#${idName}`).text(status);

        const $el = $(`#${idName}`);
        $el.removeClass('val-safe val-warning val-danger');
        if(status === '存活') $el.addClass('val-safe');
        else if(status === '失踪') $el.addClass('val-warning');
        else if(status === '被捕获') $el.addClass('val-danger');
      });
    }

    // ======== 音乐播放器逻辑 ========
    window.toggleSurvivalAudio = function(btnElement) {
      const terminal = btnElement.closest('.survival-terminal');
      if(!terminal) return;

      const audio = terminal.querySelector('#terminal-audio');
      const icon = btnElement.querySelector('i');
      const visualizer = terminal.querySelector('.audio-visualizer');
      const statusText = terminal.querySelector('.audio-status-text');

      if (audio.paused) {
        audio.play();
        icon.className = 'fas fa-pause';
        visualizer.classList.add('playing');
        statusText.classList.add('playing');
        statusText.innerText = "SIGNAL PLAYING...";
      } else {
        audio.pause();
        icon.className = 'fas fa-play';
        visualizer.classList.remove('playing');
        statusText.classList.remove('playing');
        statusText.innerText = "SIGNAL DETECTED";
      }
    };

    // ======== 初始化与事件绑定 ========
    async function init() {
      if(typeof waitGlobalInitialized === 'function') {
        await waitGlobalInitialized('Mvu');
        populateCharacterData();
        eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, () => {
          populateCharacterData();
        });
      }

      // 调整所有已有音频的状态（防止多个终端面板冲突）
      const audioElements = document.querySelectorAll('#terminal-audio');
      audioElements.forEach(el => {
         el.volume = 0.6; // 设置合适的默认音量
      });
    }

    if(typeof errorCatched === 'function') {
      $(errorCatched(init));
    } else {
      document.addEventListener('DOMContentLoaded', init);
    }
  </script>
